import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized string for the current locale.
///
/// Used for parameter labels and option descriptions.
typedef LocalizedText = String Function(AppLocalizations l10n);

/// The data type of a fractal parameter.
///
/// Determines how the parameter is rendered in the UI and how its
/// value is validated and stored.
enum FractalParamType {
  /// A floating-point number parameter.
  ///
  /// Rendered as a slider with continuous values.
  /// Value type: [double]
  float,

  /// An integer parameter.
  ///
  /// Rendered as a slider with discrete steps.
  /// Value type: [int]
  integer,

  /// A selection from a fixed set of options.
  ///
  /// Rendered as a dropdown or segmented control.
  /// Value type: depends on [FractalParamOption.value]
  enumeration,

  /// A boolean on/off parameter.
  ///
  /// Rendered as a switch or checkbox.
  /// Value type: [bool]
  boolean,
}

/// An option for an enumeration-type parameter.
///
/// Defines a single selectable value with its display label.
///
/// Example:
/// ```dart
/// FractalParamOption(
///   value: 0,
///   label: (l10n) => l10n.colorFire,
/// )
/// ```
class FractalParamOption {
  /// The underlying value for this option.
  ///
  /// This is what gets stored in the parameter map and passed to shaders.
  final Object value;

  /// Returns the localized display label for this option.
  final LocalizedText label;

  /// Creates a new parameter option.
  const FractalParamOption({
    required this.value,
    required this.label,
  });
}

/// Defines the schema for a configurable fractal parameter.
///
/// A [FractalParameter] describes how a single adjustable value should
/// behave: its valid range, step increment, default value, and UI
/// representation.
///
/// Parameters are defined per [FractalModule] and used to:
/// - Generate the controls UI automatically
/// - Validate user input
/// - Clamp values to valid ranges
/// - Store and restore presets
///
/// {@category Models}
///
/// Example:
/// ```dart
/// FractalParameter(
///   id: 'iterations',
///   label: (l10n) => l10n.paramIterations,
///   type: FractalParamType.integer,
///   min: 10,
///   max: 500,
///   step: 1,
///   defaultValue: 100,
/// )
/// ```
@immutable
class FractalParameter {
  /// Unique identifier for this parameter.
  ///
  /// Used as the key in parameter maps and for preset serialization.
  /// Should be a lowercase, camelCase string (e.g., 'iterations', 'colorScheme').
  final String id;

  /// Returns the localized display label for this parameter.
  ///
  /// Shown in the controls UI next to the input widget.
  final LocalizedText label;

  /// The data type of this parameter.
  ///
  /// Determines the UI widget and value handling.
  final FractalParamType type;

  /// The minimum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration] and [FractalParamType.boolean],
  /// this is typically 0.
  final double min;

  /// The maximum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration], this should match `options.length - 1`.
  final double max;

  /// The step increment for slider-based inputs.
  ///
  /// For integers, use 1.0. For floats, use an appropriate precision
  /// (e.g., 0.1 or 0.01).
  final double step;

  /// The initial value when no preset is applied.
  ///
  /// Must be within the [min]/[max] range and compatible with [type].
  final Object defaultValue;

  /// Available options for enumeration-type parameters.
  ///
  /// Only used when [type] is [FractalParamType.enumeration].
  /// Empty for other types.
  final List<FractalParamOption> options;

  /// Creates a new [FractalParameter] with the specified schema.
  ///
  /// For enumeration types, ensure [options] is populated with
  /// all valid choices.
  const FractalParameter({
    required this.id,
    required this.label,
    required this.type,
    required this.min,
    required this.max,
    required this.step,
    required this.defaultValue,
    this.options = const [],
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 rotation;

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 mousePos;

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  const FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required this.rotation,
    this.colorScheme = 0,
    required this.mousePos,
    this.fractalType = FractalType.mandelbulb,
  });

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? this.mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        rotation,
        colorScheme,
        mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'package:flutter_fractals/core/models/fractal_params.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  test('FractalParams equality includes fractalType', () {
    final a = FractalParams(
      rotation: Vector3.zero(),
      mousePos: Vector2.zero(),
      fractalType: FractalType.mandelbulb,
    );
    final b = a.copyWith(fractalType: FractalType.julia);

    expect(a, isNot(equals(b)));
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';

void main() {
  group('CommonFractalParams', () {
    test(
        'builds standard escape-time iteration parameter without changing schema',
        () {
      final parameter = CommonFractalParams.iterations(defaultValue: 160);

      expect(parameter.id, 'iterations');
      expect(parameter.type, FractalParamType.integer);
      expect(parameter.min, 20);
      expect(parameter.max, 5000);
      expect(parameter.step, 1);
      expect(parameter.defaultValue, 160);
    });

    test(
        'builds standard escape-time bailout parameter without changing schema',
        () {
      final parameter = CommonFractalParams.bailout(defaultValue: 4.0);

      expect(parameter.id, 'bailout');
      expect(parameter.type, FractalParamType.float);
      expect(parameter.min, 2.0);
      expect(parameter.max, 8.0);
      expect(parameter.step, 0.1);
      expect(parameter.defaultValue, 4.0);
    });

    test(
        'builds four-palette 3D color scheme parameter without changing options',
        () {
      final parameter = CommonFractalParams.colorScheme4(defaultValue: 0);

      expect(parameter.id, 'colorScheme');
      expect(parameter.type, FractalParamType.enumeration);
      expect(parameter.min, 0);
      expect(parameter.max, 3);
      expect(parameter.step, 1);
      expect(parameter.defaultValue, 0);
      expect(parameter.options.map((option) => option.value), [0, 1, 2, 3]);
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/builders/built_in_preset_contract.dart';
import 'package:flutter_fractals/core/modules/builders/uniform_layout.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 2D escape-time fractal.
///
/// Adding a new escape-time fractal = one [EscapeTimeConfig] + one .frag shader.
/// No Dart module file needed.
class EscapeTimeConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final double defaultIterations;
  final double defaultBailout;
  final int defaultColorScheme;
  final double defaultCenterX;
  final double defaultCenterY;
  final double defaultZoom;
  final int maxIterations;
  final String category;
  final List<FractalParameter> extraParams;
  final List<FractalPreset> extraPresets;

  const EscapeTimeConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.defaultIterations = 120,
    this.defaultBailout = 4.0,
    this.defaultColorScheme = 0,
    this.defaultCenterX = 0.0,
    this.defaultCenterY = 0.0,
    this.defaultZoom = 1.0,
    // Most runtime_effect escape-time shaders compile with a static loop cap of 500.
    // Keep the UI/params cap aligned with shader reality to avoid misleading controls.
    this.maxIterations = 500,
    this.category = 'Escape-Time',
    this.extraParams = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [EscapeTimeConfig].
///
/// All standard escape-time fractals share the same uniform layout:
///   float 0: uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uCenter (vec2)
///   float 5: uZoom
///   float 6: uIterations
///   float 7: uBailout
///   float 8: uColorScheme
///   float 9: uTransparentBg
///   float 10+: extra params (in order)
///
/// This eliminates per-fractal Dart boilerplate.
FractalModule buildEscapeTimeModule(EscapeTimeConfig config) {
  assert(
    config.extraParams.every((p) => p.defaultValue is num),
    'Escape-time extra parameters must have numeric defaults because they are written to float uniforms.',
  );

  final defaults = _resolveEscapeTimeDefaults(config);

  final parameters = [
    CommonFractalParams.iterations(
      defaultValue: defaults.iterations,
      max: config.maxIterations,
    ),
    CommonFractalParams.bailout(defaultValue: config.defaultBailout),
    CommonFractalParams.colorScheme64(defaultValue: config.defaultColorScheme),
    ...config.extraParams,
  ];

  final defaultParams = <String, Object>{
    'iterations': defaults.iterations,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
  };
  for (final p in config.extraParams) {
    defaultParams[p.id] = p.defaultValue;
  }

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2(defaults.centerX, defaults.centerY),
      zoom: defaults.zoom,
      rotation: Vector3.zero(),
    ),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.twoD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: buildBuiltInPresetList(
      defaultPreset: defaultPreset,
      extraPresets: config.extraPresets,
    ),
    setUniforms: (shader, state, size, time) {
      shader.setFloat(EscapeTimeUniformSlots.time, time);
      shader.setFloat(EscapeTimeUniformSlots.resolutionX, size.width);
      shader.setFloat(EscapeTimeUniformSlots.resolutionY, size.height);
      shader.setFloat(EscapeTimeUniformSlots.centerX, state.view.pan.x);
      shader.setFloat(EscapeTimeUniformSlots.centerY, state.view.pan.y);
      shader.setFloat(EscapeTimeUniformSlots.zoom, state.view.zoom);
      shader.setFloat(EscapeTimeUniformSlots.iterations,
          readDouble(state.params, 'iterations', defaults.iterations));
      shader.setFloat(EscapeTimeUniformSlots.bailout,
          readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          EscapeTimeUniformSlots.colorScheme,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(EscapeTimeUniformSlots.transparentBackground,
          state.transparentBackground ? 1.0 : 0.0);
      for (int i = 0; i < config.extraParams.length; i++) {
        final p = config.extraParams[i];
        shader.setFloat(EscapeTimeUniformSlots.extraStart + i,
            readDouble(state.params, p.id, (p.defaultValue as num).toDouble()));
      }
    },
  );
}

class _EscapeTimeDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _EscapeTimeDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_EscapeTimeDefaults _resolveEscapeTimeDefaults(EscapeTimeConfig config) {
  var effectiveIterations = config.defaultIterations;
  var effectiveCenterX = config.defaultCenterX;
  var effectiveCenterY = config.defaultCenterY;
  var effectiveZoom = config.defaultZoom;

  if (config.extraPresets.isNotEmpty) {
    // If the module has curated presets, use the first curated preset as
    // default framing/iterations so each fractal starts with a distinctive
    // initial state instead of generic (0,0,1,120).
    final curated = config.extraPresets.first;
    final it = curated.params['iterations'];
    if (it is num) {
      effectiveIterations = it.toDouble();
    }
    // Only use first preset's view if no explicit center/zoom was configured.
    final hasExplicitView = config.defaultCenterX != 0.0 ||
        config.defaultCenterY != 0.0 ||
        config.defaultZoom != 1.0;
    if (!hasExplicitView) {
      effectiveCenterX = curated.view.pan.x;
      effectiveCenterY = curated.view.pan.y;
      effectiveZoom = curated.view.zoom;
    }
  } else {
    // For modules that still use baseline constructor defaults, generate
    // deterministic per-module defaults from the module id.
    final autoDefaults = _autoDefaultsForModule(config.id);
    final usesBaseIterations = config.defaultIterations == 120;
    final usesBaseCenter =
        config.defaultCenterX == 0.0 && config.defaultCenterY == 0.0;
    final usesBaseZoom = config.defaultZoom == 1.0;

    if (usesBaseIterations) {
      effectiveIterations = autoDefaults.iterations;
    }
    if (usesBaseCenter) {
      effectiveCenterX = autoDefaults.centerX;
      effectiveCenterY = autoDefaults.centerY;
    }
    if (usesBaseZoom) {
      effectiveZoom = autoDefaults.zoom;
    }
  }

  return _EscapeTimeDefaults(
    centerX: effectiveCenterX,
    centerY: effectiveCenterY,
    zoom: effectiveZoom.clamp(0.2, 32.0),
    iterations:
        effectiveIterations.clamp(20.0, config.maxIterations.toDouble()),
  );
}

class _AutoModuleDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _AutoModuleDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_AutoModuleDefaults _autoDefaultsForModule(String moduleId) {
  final hash = _fnv1a32(moduleId);

  double unit(int shift) => ((hash >> shift) & 0xFF) / 255.0;

  // Keep defaults stable but non-generic per module:
  // - center around the classic Mandelbrot neighborhood
  // - moderate zoom that still shows structure
  // - varied iteration density for immediate detail diversity
  final centerX = -0.55 + (unit(0) - 0.5) * 0.5; // [-0.80, -0.30]
  final centerY = (unit(8) - 0.5) * 0.4; // [-0.20, 0.20]
  final zoom = 0.65 + unit(16) * 0.9; // [0.65, 1.55]
  final iterations = 110.0 + (hash % 131); // [110, 240]

  return _AutoModuleDefaults(
    centerX: centerX,
    centerY: centerY,
    zoom: zoom,
    iterations: iterations,
  );
}

int _fnv1a32(String text) {
  var hash = 0x811C9DC5;
  for (final codeUnit in text.codeUnits) {
    hash ^= codeUnit;
    hash = (hash * 0x01000193) & 0xFFFFFFFF;
  }
  return hash;
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';

/// Stable provenance marker for generated built-in presets.
///
/// Builder-owned presets are part of the app catalog, not user-created data, so
/// their metadata must be replayable across registry rebuilds and test runs.
final builtInPresetCreatedAt = DateTime.utc(2025, 1, 1);

/// Returns the builder-facing built-in preset list with replayable metadata.
///
/// Catalog entries often provide curated [extraPresets] for params/view only.
/// Normalize them here so callers cannot accidentally surface mutable-looking or
/// non-replayable presets in [FractalModule.builtInPresets].
List<FractalPreset> buildBuiltInPresetList({
  required FractalPreset defaultPreset,
  required List<FractalPreset> extraPresets,
}) {
  final usedIds = <String>{};
  return [
    defaultPreset.copyWith(
      id: _uniquePresetId('${defaultPreset.moduleId}-classic', usedIds),
      name: 'Classic',
    ),
    ...extraPresets.map((preset) => _asReplayableBuiltInPreset(
          preset,
          usedIds,
        )),
  ];
}

FractalPreset _asReplayableBuiltInPreset(
  FractalPreset preset,
  Set<String> usedIds,
) {
  return preset.copyWith(
    id: _uniquePresetId(preset.id, usedIds),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );
}

String _uniquePresetId(String id, Set<String> usedIds) {
  if (usedIds.add(id)) return id;

  var suffix = 2;
  while (true) {
    final candidate = '$id-$suffix';
    if (usedIds.add(candidate)) return candidate;
    suffix++;
  }
}

/// Uniform slot contracts shared by declarative module builders.
///
/// Keep these indices aligned with the matching fragment shaders. Centralizing
/// them makes shader/builder drift visible during review instead of burying the
/// contract as repeated magic numbers in setUniforms closures.
abstract final class EscapeTimeUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int centerX = 3;
  static const int centerY = 4;
  static const int zoom = 5;
  static const int iterations = 6;
  static const int bailout = 7;
  static const int colorScheme = 8;
  static const int transparentBackground = 9;
  static const int extraStart = 10;
}

abstract final class Raymarched3DUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int mouseX = 3;
  static const int mouseY = 4;
  static const int zoom = 5;
  static const int rotationX = 6;
  static const int rotationY = 7;
  static const int rotationZ = 8;
  static const int power = 9;
  static const int iterations = 10;
  static const int steps = 11;
  static const int bailout = 12;
  static const int colorScheme = 13;
  static const int fractalType = 14;
  static const int transparentBackground = 15;
}

