import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  const FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required this.params,
    required this.view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  });

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map)
          .map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_builder.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';

/// Catalog ID integrity tests (P0 #4).
///
/// These tests act as a lock on the catalog — any accidental rename,
/// removal, or duplication of a catalog ID will be caught here.
///
/// ## Expected counts (update when catalog intentionally grows)
///
/// - Escape-time catalog unique top-level IDs : 490
/// - Raymarched-3D catalog unique IDs         :   9
/// - Custom hand-built modules                :   6
///   (julia, julia_dual, phoenix, nova, mandelbulb, mandelbox)
/// - Total ModuleRegistry modules (non-debug) : 505
///
/// The "196 GPU shaders" figure in TODO.md refers to fragment shader
/// assets compiled at build time; it predates the full catalog expansion.
void main() {
  // ---------------------------------------------------------------------------
  // 1. Escape-time catalog — raw entries
  // ---------------------------------------------------------------------------
  group('EscapeTimeConfig catalog entries', () {
    late final List<EscapeTimeConfig> catalog;

    setUpAll(() {
      catalog = escapeTimeCatalog;
    });

    test('total entry count is 491 (including 1 known duplicate)', () {
      expect(catalog.length, 491,
          reason: 'Update this constant when new entries are intentionally '
              'added to escape_time_catalog.dart.');
    });

    test('all IDs match pattern: lowercase alphanumeric + underscores', () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = catalog
          .map((c) => c.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty,
          reason: 'IDs must be lowercase alphanumeric + underscores. '
              'Bad IDs: $bad');
    });

    test('no catalog entry has an empty name', () {
      final empty = catalog.where((c) => c.name.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must have a non-empty name.');
    });

    test('no catalog entry has an empty shader asset path', () {
      final empty = catalog.where((c) => c.shaderAsset.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must declare a shaderAsset path.');
    });

    // Snapshot test: any rename/removal/addition will fail here.
    // Update this list when intentionally changing catalog IDs.
    test('snapshot — first 20 catalog IDs are stable', () {
      final expected = [
        'mandelbrot',
        'burning_ship',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'nova_julia',
        'fatou',
        'gamma_fractal',
        'perpendicular_mandelbrot',
        'lambda',
        'magnet_type_1',
        'magnet_type_2',
        'magnet_type_3',
        'power_sum',
        'cactus',
        'astroid',
        'deltoid',
        'eisenstein',
        'druid',
      ];
      final actual = catalog.take(20).map((c) => c.id).toList();
      expect(actual, expected,
          reason: 'First-20 catalog IDs changed. '
              'If intentional, update this snapshot.');
    });
  });

  // ---------------------------------------------------------------------------
  // 2. ModuleRegistry — built registry (release mode, no debug modules)
  // ---------------------------------------------------------------------------
  group('ModuleRegistry integrity', () {
    late final ModuleRegistry registry;

    setUpAll(() {
      registry = ModuleRegistry();
    });

    test('total module count is 505 (non-debug)', () {
      // Debug-only diagnostic modules are excluded in release/test builds
      // because kDebugMode is false in test environments.
      expect(registry.modules.length, 505,
          reason: 'Update this constant when new modules are intentionally '
              'added. Current breakdown: 355 escape-time + 9 raymarched-3D '
              '+ 6 custom = 370.');
    });

    test('all module IDs are unique (no duplicates)', () {
      final ids = registry.modules.map((m) => m.id).toList();
      final seen = <String>{};
      final dupes = <String>[];
      for (final id in ids) {
        if (!seen.add(id)) dupes.add(id);
      }
      expect(dupes, isEmpty,
          reason: 'Duplicate module IDs detected: $dupes. '
              'The registry deduplicates, but duplicates in the raw catalog '
              'waste entries.');
    });

    test('all module IDs match pattern: lowercase alphanumeric + underscores',
        () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = registry.modules
          .map((m) => m.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty, reason: 'Non-conforming module IDs: $bad');
    });

    test('no module has an empty shader asset path', () {
      final empty = registry.modules
          .where((m) => m.shaderAsset.trim().isEmpty)
          .map((m) => m.id)
          .toList();
      expect(empty, isEmpty,
          reason: 'Every module must declare a non-empty shaderAsset. '
              'Missing: $empty');
    });

    test('byId lookup succeeds for mandelbrot', () {
      expect(() => registry.byId('mandelbrot'), returnsNormally);
      expect(registry.byId('mandelbrot').id, 'mandelbrot');
    });

    test('byId lookup succeeds for all custom hand-built modules', () {
      const customIds = [
        'julia',
        'julia_dual',
        'phoenix',
        'nova',
        'mandelbulb',
        'mandelbox',
      ];
      for (final id in customIds) {
        expect(
          () => registry.byId(id),
          returnsNormally,
          reason: 'Custom module "$id" not found in registry.',
        );
      }
    });

    // Snapshot of known-stable IDs. Removing or renaming any of these will
    // fail this test, prompting an intentional update.
    test('snapshot — known stable module IDs are present', () {
      const knownIds = [
        'mandelbrot',
        'julia',
        'julia_dual',
        'burning_ship',
        'phoenix',
        'nova',
        'nova_julia',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'mandelbulb',
        'mandelbox',
        'kifs_menger',
        'kifs_sierpinski_tetra',
        'quaternion_julia_3d',
      ];
      final registryIds = registry.modules.map((m) => m.id).toSet();
      final missing = knownIds.where((id) => !registryIds.contains(id));
      expect(missing, isEmpty,
          reason: 'Previously-present module IDs are missing: $missing. '
              'If intentional, update this snapshot.');
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Common parameter builders shared across many 2D modules.
///
/// Keep these helpers small and stable; they are used in tests and codegen later.
class CommonFractalParams {
  static const int paletteCount = 64;

  static FractalParameter iterations({
    required num defaultValue,
    num min = 20,
    num max = 5000,
  }) {
    return FractalParameter(
      id: 'iterations',
      label: (l10n) => l10n.paramIterations,
      type: FractalParamType.integer,
      min: min.toDouble(),
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter bailout({
    required double defaultValue,
    double min = 2.0,
    double max = 8.0,
  }) {
    return FractalParameter(
      id: 'bailout',
      label: (l10n) => l10n.paramBailout,
      type: FractalParamType.float,
      min: min,
      max: max,
      step: 0.1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter colorScheme4({Object defaultValue = 0, num max = 3}) {
    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
      options: [
        FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
        FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
        FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
        FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      ],
    );
  }

  /// Color cycle speed for palette-texture shaders (G15).
  ///
  /// A value of 0.0 = static (no cycling); 0.1 = ~1 full cycle every 10 s.
  /// Only meaningful at deep zoom where the perturbation shader is active
  /// (zoom >= 5e6). The controls panel shows this slider for all modules that
  /// include it, but it only has visible effect in the perturbation path.
  static FractalParameter colorCycleSpeed() {
    return FractalParameter(
      id: 'colorCycleSpeed',
      label: (l10n) => 'Color speed',
      type: FractalParamType.float,
      min: 0.0,
      max: 0.2,
      step: 0.001,
      defaultValue: 0.0,
    );
  }

  static FractalParameter colorScheme64({int defaultValue = 0}) {
    // Keep the first 4 as named palettes for continuity.
    final options = <FractalParamOption>[
      FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
      FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
      FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
      FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      // Remaining palettes are numbered. Keep labels simple for screen readers.
      // Palette 5 reserved for legacy Phoenix palette name.
      FractalParamOption(value: 4, label: (l10n) => l10n.colorPhoenix),
      for (int i = 5; i < paletteCount; i++)
        FractalParamOption(
          value: i,
          label: (AppLocalizations l10n) => 'Palette ${i + 1}',
        ),
    ];

    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: paletteCount - 1,
      step: 1,
      defaultValue: defaultValue,
      options: options,
    );
  }
}

